import "./App.css";
import Header from "./Components/Header";
import AdminDash from "./pages/AdminDash";
import CustomerDash from "./pages/CustomerDash";
import Login from "./pages/Login";
import { Routes, Route, Navigate } from "react-router-dom";
import TechnicianDash from "./pages/TechnicianDash";
import { useState } from "react";
import { useEffect } from "react";
import AddUser from "./pages/AddUser";
import AdminLayout from "./layouts/AdminLayout";
import AddEmployee from "./pages/AddEmployee";
import EditUsers from "./pages/EditUsers";
import EditEmployees from "./pages/EditEmployees";
import RepairRequests from "./pages/RepairRequests";
import Report from "./pages/Report";

function App() {
  const [user, setUser] = useState(null);

  useEffect(() => {
    const savedUser = localStorage.getItem("user");
    if (savedUser) {
      setUser(JSON.parse(savedUser));
    }
  }, []);

  const handleLogout = () => {
    localStorage.removeItem("user");
    setUser(null);
  };

  return (
    <div className="app-container">
      <Header user={user} handleLogout={handleLogout} />
      <main className="content">
        <Routes>
          <Route path="/" element={<Navigate to="/login" />} />
          <Route path="/login" element={<Login setUser={setUser}/>} />

          <Route
            path="/admin"
            element={
              user?.role === "ADMIN" ? <AdminLayout /> : <Navigate to="/login" />
            }
          >
            <Route index element={<AdminDash />} />
            <Route path="repair-requests" element={<RepairRequests />} />
            <Route path="add-user" element={<AddUser />} />
            <Route path="edit-users" element={<EditUsers />} />
            <Route path="edit-user" element={<Navigate to="/admin/edit-users" replace />} />
            <Route path="add-employee" element={<AddEmployee />} />
            <Route path="edit-employees" element={<EditEmployees />} />
            <Route
              path="edit-employee"
              element={<Navigate to="/admin/edit-employees" replace />}
            />
            <Route path="report" element={<Report />} />
          </Route>

          <Route
            path="/customerDashboard"
            element={
              user?.role === "CUSTOMER" ? (
                <CustomerDash />
              ) : (
                <Navigate to="/login" />
              )
            }
          />

          <Route
            path="/technicianDashboard"
            element={
              user?.role === "TECHNICIAN" ? (
                <TechnicianDash />
              ) : (
                <Navigate to="/login" />
              )
            }
          />
        </Routes>
      </main>
      {/* <Footer /> */}
    </div>
  );
}

export default App;

import React, { useMemo, useState } from "react";
import { Outlet, useLocation, useNavigate } from "react-router-dom";
import Sidebar from "../Components/Sidebar";
import "../styles/AdminLayout.css";

const AdminLayout = () => {
  const navigate = useNavigate();
  const location = useLocation();

  const [users, setUsers] = useState([
    {
      id: 1,
      name: "Nila Thomas",
      username: "nila.customer",
      email: "nila@email.com",
      role: "CUSTOMER",
    },
    {
      id: 2,
      name: "Ravi Menon",
      username: "ravi.tech",
      email: "ravi@email.com",
      role: "TECHNICIAN",
    },
  ]);

  const [employees, setEmployees] = useState([
    { id: 1, name: "Karan V", email: "karan@serviceflow.com", team: "On-site" },
    { id: 2, name: "Maya J", email: "maya@serviceflow.com", team: "Field Service" },
  ]);

  const [repairRequests, setRepairRequests] = useState([
    { id: 1001, customer: "Nila Thomas", issue: "AC not cooling", status: "OPEN" },
    { id: 1002, customer: "Rahul Das", issue: "Water leakage", status: "IN_PROGRESS" },
    { id: 1003, customer: "Sonia M", issue: "Noisy motor", status: "DONE" },
  ]);

  const menuItems = [
    { label: "Dashboard", to: "/admin", end: true, icon: "fa-solid fa-grip" },
    {
      label: "Repair Request",
      to: "/admin/repair-requests",
      icon: "fa-solid fa-screwdriver-wrench",
    },
    { label: "Add User", to: "/admin/add-user", icon: "fa-solid fa-user-plus" },
    { label: "Edit Users", to: "/admin/edit-users", icon: "fa-solid fa-user-pen" },
    {
      label: "Add Employee",
      to: "/admin/add-employee",
      icon: "fa-solid fa-user-plus",
    },
    {
      label: "Edit Employees",
      to: "/admin/edit-employees",
      icon: "fa-solid fa-user-pen",
    },
    { label: "Report", to: "/admin/report", icon: "fa-solid fa-book" },
  ];

  const currentLabel =
    menuItems.find((item) => {
      if (item.end) {
        return location.pathname === item.to;
      }
      return location.pathname.startsWith(item.to);
    })?.label || "Dashboard";

  const dataApi = useMemo(
    () => ({
      users,
      employees,
      repairRequests,
      addUser: (payload) => {
        setUsers((prev) => [
          ...prev,
          { id: Date.now(), ...payload },
        ]);
      },
      updateUser: (id, payload) => {
        setUsers((prev) => prev.map((user) => (user.id === id ? { ...user, ...payload } : user)));
      },
      removeUser: (id) => {
        setUsers((prev) => prev.filter((user) => user.id !== id));
      },
      addEmployee: (payload) => {
        setEmployees((prev) => [
          ...prev,
          { id: Date.now(), ...payload },
        ]);
      },
      updateEmployee: (id, payload) => {
        setEmployees((prev) =>
          prev.map((employee) => (employee.id === id ? { ...employee, ...payload } : employee)),
        );
      },
      removeEmployee: (id) => {
        setEmployees((prev) => prev.filter((employee) => employee.id !== id));
      },
      updateRepairStatus: (id, status) => {
        setRepairRequests((prev) =>
          prev.map((request) => (request.id === id ? { ...request, status } : request)),
        );
      },
      summary: {
        usersCount: users.length,
        employeesCount: employees.length,
        openRepairs: repairRequests.filter((request) => request.status !== "DONE").length,
        completedRepairs: repairRequests.filter((request) => request.status === "DONE").length,
      },
    }),
    [users, employees, repairRequests],
  );

  const onLogout = () => {
    localStorage.removeItem("user");
    navigate("/login");
  };

  return (
    <div className="adminShell">
      <Sidebar items={menuItems} />
      <div className="adminMain">
        <div className="adminTopBar">
          <h2>{currentLabel}</h2>

        </div>
        <div className="adminOutlet">
          <Outlet context={dataApi} />
        </div>
      </div>
    </div>
  );
};

export default AdminLayout;

import React, { useState } from "react";
import { useNavigate, useOutletContext } from "react-router-dom";
import "../styles/AdminPages.css";

function AddUser() {
  const { addUser } = useOutletContext();
  const navigate = useNavigate();
  const [form, setForm] = useState({
    name: "",
    username: "",
    email: "",
    role: "CUSTOMER",
  });

  const onChange = (event) => {
    setForm((prev) => ({ ...prev, [event.target.name]: event.target.value }));
  };

  const onSubmit = (event) => {
    event.preventDefault();
    // addUser(form);
    // navigate("/admin/edit-users");
    try {
      const res = await fetch("http://localhost:8080/api/auth/add");

    } catch (error) {
      console.log(`Error Adding User: ${error}`)
    }
  };

  return (
    <form className="formGrid" onSubmit={onSubmit}>
      <input
        className="textInput"
        name="name"
        value={form.name}
        onChange={onChange}
        placeholder="Full name"
        required
      />
      <input
        className="textInput"
        name="username"
        value={form.username}
        onChange={onChange}
        placeholder="Username"
        required
      />
      <input
        className="textInput"
        name="email"
        type="email"
        value={form.email}
        onChange={onChange}
        placeholder="Email"
        required
      />
      <select className="selectInput" name="role" value={form.role} onChange={onChange}>
        <option value="CUSTOMER">Customer</option>
        <option value="TECHNICIAN">Technician</option>
        <option value="ADMIN">Admin</option>
      </select>
      <button className="primaryBtn" type="submit">
        Save User
      </button>
    </form>
  );
}

export default AddUser;
